        int q = p;
        while (q + 1 < n && nums[q] > nums[q + 1]) {
            q++;
        }

        // Find the end point r (strictly increasing)
        int r = q;
        while (r + 1 < n && nums[r] < nums[r + 1]) {
            r++;
