        for r in l+3..<nums.count {
            // Check if nums[l...r] is a valid 3-part subarray
            var isStrictlyIncreasing = true
            var isStrictlyDecreasing = true
            var isStrictlyIncreasingAgain = true

            // Check if there exists p and q such that the conditions are satisfied
            for i in l..<r {
                if i == l {
                    continue
                }
                if nums[i] <= nums[i-1] {
                    isStrictlyIncreasing = false
                }
            }

            for i in l+1..<r {
                if i == r-1 {
                    continue
                }
                if nums[i] >= nums[i-1] {
                    isStrictlyDecreasing = false
                }
            }

            for i in l+2..<r {
