                    continue
                }
                if nums[i] <= nums[i-1] {
                    isStrictlyIncreasingAgain = false
                }
            }

            if isStrictlyIncreasing && isStrictlyDecreasing && isStrictlyIncreasingAgain {
                let currentSum = nums[l...r].reduce(0, +)
                maxSum = max(maxSum, currentSum)
            }
        }
    }

